import statistics

def aggregate_by_region(rows: list[dict]) -> dict:
    """Aggregates total sales amounts per region."""
    by_region = {}
    for row in rows:
        r = row["region"]
        if r not in by_region:
            by_region[r] = []
        by_region[r].append(row["amount"])

    # Stats per region
    region_stats = {}
    for region, amounts in by_region.items():
        region_stats[region] = {
            "total": sum(amounts),
            "mean": statistics.mean(amounts),
            "median": statistics.median(amounts),
            "count": len(amounts),
        }
    return region_stats

def top_products(rows: list[dict], n: int = 5) -> list[dict]:
    """Finds the top N products by total sales amount."""
    by_product = {}
    for row in rows:
        p = row["product"]
        by_product[p] = by_product.get(p, 0) + row["amount"]

    # Convert and sort
    sorted_products = sorted(by_product.items(), key=lambda x: x[1], reverse=True)
    return [{"product": p, "total": t} for p, t in sorted_products[:n]]

import json
from pathlib import Path
from typing import Dict

def build_report(total_records: int, region_stats: dict, top_products: list[dict]) -> dict:
    """Consolidates all results into a final report dictionary."""
    return {
        "total_records": total_records,
        "region_stats": region_stats,
        "top_products": top_products,
    }

def save_report(report: dict, output_path: Path):
    """Saves the report dictionary to a JSON file."""
    Path(output_path).write_text(json.dumps(report, indent=2))
